        if (!isArray(obj)) return [];
        const n = obj.length;
        let s = node.start !== null ? Math.floor(toNumber(evalNode(node.start, env))) : 0;
        let e = node.end !== null ? Math.floor(toNumber(evalNode(node.end, env))) : n;
        if (s < 0) s = Math.max(0, n + s);
        if (e < 0) e = Math.max(0, n + e);
