      out.r = (p0.r || 0) * (1 - f) + (p1.r || 0) * f;
      out.g = (p0.g || 0) * (1 - f) + (p1.g || 0) * f;
      out.b = (p0.b || 0) * (1 - f) + (p1.b || 0) * f;
