      if (!fmt || typeof fmt !== 'string') return String(v);
      // Strip outer LaTeX math if present (we'll re-wrap before stripLaTeX).
      const m = fmt.match(/^\$(.*)\$$/);
      const inner = m ? m[1] : fmt;
      // Match a printf token: %[flags][width][.precision][specifier]
