          if ('palette' in a && Array.isArray(a.palette)) pens = a.palette;
          if ('f' in a && Array.isArray(a.f)) data = a.f;
          if ('pic' in a && a.pic && a.pic._tag === 'picture') target = a.pic;
          if ('N' in a && typeof a.N === 'number') gridN = Math.round(a.N);
