      if (!data || !initial || !final || !pens || pens.length === 0) return _emptyBounds();
      const nx = data.length;
      if (nx === 0) return _emptyBounds();
      const ny = (data[0] && data[0].length) || 0;
      if (ny === 0) return _emptyBounds();
