          // Interval 0: Red→Magenta (R=1, G=0, B: 0→1)
          // Interval 1: Magenta→Blue (R: 1→0, G=0, B=1)
          // Interval 2: Blue→Cyan (R=0, G: 0→1, B=1)
          // Interval 3: Cyan→Green (R=0, G=1, B: 1→0)
