        makeTriple(ax, ay, az), makeTriple(bx, ay, az),
        makeTriple(ax, by, az), makeTriple(bx, by, az),
        makeTriple(ax, ay, bz), makeTriple(bx, ay, bz),
        makeTriple(ax, by, bz), makeTriple(bx, by, bz),
