    // hatch()/crosshatch() looks far too thin in HiTeXeR. Boost only thin/default
    // pens; an explicit thick hatch pen (e.g. hatch(black+2bp)) keeps its width.
    let lwBp = (spec.pen && spec.pen.linewidth) || 0.5;
    if (lwBp <= 0.6) lwBp *= 2.5;
