    const cp1x = (s.cp1.x - minX)*scaleX, cp1y = (maxY - s.cp1.y)*scaleY;
    const cp2x = (s.cp2.x - minX)*scaleX, cp2y = (maxY - s.cp2.y)*scaleY;
    const p3x = (s.p3.x - minX)*scaleX, p3y = (maxY - s.p3.y)*scaleY;

